"""
ptzhelper.py - PTZHelper Device Control Library
Shared by PTZ_STARTUP / PTZ_FUNCTION / PTZ_LIMIT / PTZ_SPEED / PTZ_ASTRO
P0 Infrastructure: directory creation, LOG system, config, interaction utilities
"""

import os, sys, time, json, re, requests, shutil, getpass
from datetime import datetime
from requests.auth import HTTPDigestAuth

# Simulator override
_SIMULATOR_IP = os.environ.get('SIMULATOR_IP')

# ===== P0.1 Directory paths =====
SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
