CREDS_FILE = os.path.join(SCRIPT_DIR, 'device_credentials.json')
PTZ_CONFIG_FILE = os.path.join(SCRIPT_DIR, 'PTZ_CONFIG.json')
LOCAL_CONFIG_FILE = os.path.join(SCRIPT_DIR, 'LOCAL_CONFIG.json')
DEVICE_CONFIG_FILE = os.path.join(SCRIPT_DIR, 'device_config.json')
LIMIT_MAP_FILE = os.path.join(SCRIPT_DIR, 'data', 'limit_map.json')

REQUIRED_DIRS = ['record', 'log', 'report', 'download']

def p0_ensure_dirs(base_dir=None):
    """P0.1: Create required directories at script startup"""
    base = base_dir or SCRIPT_DIR
    created = []
    for d in REQUIRED_DIRS:
        path = os.path.join(base, d)
        if not os.path.exists(path):
            os.makedirs(path, exist_ok=True)
            created.append(d)
    return created

# ===== LOG system (P0.2/P0.3) =====
LOG_FILE = None
LOG_SEQ = 0

def log_init():
    """P0.2: Create LOG file with yyyymmdd-NNN naming"""
    global LOG_FILE, LOG_SEQ
    LOG_DIR = os.path.join(SCRIPT_DIR, 'log')
    os.makedirs(LOG_DIR, exist_ok=True)
    ts = datetime.now().strftime('%Y%m%d')
    existing = [f for f in os.listdir(LOG_DIR) if f.startswith(f'log_{ts}-')]
    LOG_SEQ = len(existing) + 1
    LOG_FILE = os.path.join(LOG_DIR, f'log_{ts}-{LOG_SEQ:03d}.md')
    with open(LOG_FILE, 'w', encoding='utf-8') as f:
        f.write(f'# PTZ_ASTRO Log Session {LOG_SEQ:03d}\n')
        f.write(f'Started: {datetime.now().strftime("%Y-%m-%d %H:%M:%S")}\n')
        f.write(f'{"="*60}\n\n')
    return LOG_FILE

def _log_write(level, msg):
    """P0.3: Write LOG with [level] yyyy-mm-dd HH:MM:SS.mss format"""
    now = datetime.now()
    ts = now.strftime('%Y-%m-%d %H:%M:%S') + f'.{now.microsecond // 1000:03d}'
    line = f'[{level.upper():7s}] {ts} {msg}'
    try:
        print(line)
    except UnicodeEncodeError:
        print(line.encode('gbk', errors='replace').decode('gbk'))
    if LOG_FILE:
        try:
            with open(LOG_FILE, 'a', encoding='utf-8') as f:
                f.write(line + '\n')
        except Exception:
            pass

def log_info(msg):   _log_write('info', msg)
def log_warn(msg):   _log_write('warning', msg)
def log_err(msg):    _log_write('error', msg)
def log_done(msg):   _log_write('done', msg)
def log_fail(msg):   _log_write('failed', msg)

# ===== P0.4 config.json =====
def p0_init_config():
    """P0.4: Initialize config.json with device info list structure"""
    if not os.path.exists(CONFIG_FILE):
        default = {
            'devices': [],
            'selected_interface': None,
            'last_scan': None
        }
        safe_write_json(CONFIG_FILE, default)
        log_info('P0.4: config.json initialized')
    return safe_read_json(CONFIG_FILE) or {'devices': [], 'selected_interface': None}

def add_device_to_config(device_info):
    """Add/update device in config.json by MAC as unique key"""
    cfg = safe_read_json(CONFIG_FILE) or {'devices': [], 'selected_interface': None}
    mac = device_info.get('mac', '')
    for i, dev in enumerate(cfg['devices']):
        if dev.get('mac', '').lower() == mac.lower():
            cfg['devices'][i].update(device_info)
            safe_write_json(CONFIG_FILE, cfg)
            return i
    cfg['devices'].append(device_info)
    safe_write_json(CONFIG_FILE, cfg)
    return len(cfg['devices']) - 1

# ===== Safe JSON =====
def safe_read_json(path):
    if not os.path.exists(path):
        return None
    try:
        with open(path, 'r', encoding='utf-8') as f:
            content = f.read()
            if content.startswith('\ufeff'):
                content = content[1:]
            return json.loads(content)
    except Exception:
        return None

def safe_write_json(path, data):
    """Write .tmp -> verify -> overwrite"""
    tmp = path + '.tmp'
    with open(tmp, 'w', encoding='utf-8') as f:
        json.dump(data, f, indent=2, ensure_ascii=False)
    with open(tmp, 'r', encoding='utf-8') as f:
        verified = json.load(f)
    shutil.move(tmp, path)

def append_record(config_path, record):
    data = safe_read_json(config_path) or {}
    if 'records' not in data:
        data['records'] = []
    data['records'].append(record)
    safe_write_json(config_path, data)

