# ===== PTZHelper class =====
class PTZHelper:
    def __init__(self, ip, auth):
        self.ip = _SIMULATOR_IP if _SIMULATOR_IP else ip
        self._original_ip = ip
        self.auth = HTTPDigestAuth(auth[0], auth[1])
        self.session = requests.Session()
        self.session.trust_env = False
        for k in list(os.environ.keys()):
            if 'proxy' in k.lower():
                os.environ.pop(k, None)

    def _clear_proxy(self):
        for k in list(os.environ.keys()):
            if 'proxy' in k.lower():
                os.environ.pop(k, None)

    def get_status(self, retries=2):
        self._clear_proxy()
        for attempt in range(retries + 1):
            try:
                r = self.session.get(
                    f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/status',
                    auth=self.auth, timeout=5)
                if r.status_code != 200:
                    if attempt < retries:
                        time.sleep(0.5)
                        continue
                    return {'azimuth': 0, 'elevation': 0, 'zoom': 0}
                text = r.text
                az_m = re.search(r'<azimuth>(\d+)</azimuth>', text)
                el_m = re.search(r'<elevation>(-?\d+)</elevation>', text)
                zm_m = re.search(r'<absoluteZoom>(\d+)</absoluteZoom>', text)
                return {
                    'azimuth': int(az_m.group(1)) if az_m else 0,
                    'elevation': int(el_m.group(1)) if el_m else 0,
                    'zoom': int(zm_m.group(1)) if zm_m else 0,
                }
            except Exception:
                if attempt < retries:
                    time.sleep(0.5)
                    continue
                return {'azimuth': 0, 'elevation': 0, 'zoom': 0}

    def absolute_move(self, azimuth, elevation, zoom):
        self._clear_proxy()
        xml = (f'<PTZData><AbsoluteHigh>'
              f'<azimuth>{azimuth}</azimuth>'
              f'<elevation>{elevation}</elevation>'
              f'<absoluteZoom>{zoom}</absoluteZoom>'
              f'</AbsoluteHigh></PTZData>').encode('utf-8')
        r = self.session.put(
            f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/absolute/',
            data=xml, auth=self.auth, timeout=5)
        return r.status_code == 200

    def relative_move(self, azimuth_delta, elevation_delta, zoom_delta=0):
        """P5.3: Relative move - move by delta from current position.
        PUT /ISAPI/PTZCtrl/channels/1/relative/
        """
        self._clear_proxy()
        xml = (f'<PTZData><Relative>'
              f'<azimuth>{azimuth_delta}</azimuth>'
              f'<elevation>{elevation_delta}</elevation>'
              f'<absoluteZoom>{zoom_delta}</absoluteZoom>'
              f'</Relative></PTZData>').encode('utf-8')
        try:
            r = self.session.put(
                f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/relative/',
                data=xml, auth=self.auth, timeout=5)
            return r.status_code == 200
        except Exception:
            return False

    def absolute_move_zoom(self, target_zoom):
        current = self.get_status()
        azimuth = current['azimuth']
        elevation = current['elevation']
        return self.absolute_move(azimuth, elevation, target_zoom)

    def continuous_move(self, pan=0, tilt=0, zoom=0):
        self._clear_proxy()
        xml = f'<PTZData><pan>{pan}</pan><tilt>{tilt}</tilt><zoom>{zoom}</zoom></PTZData>'.encode('utf-8')
        r = self.session.put(
            f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/continuous/',
            data=xml, auth=self.auth, timeout=5)
        return r.status_code == 200

    def stop(self):
        return self.continuous_move(0, 0, 0)

    def preset_goto(self, preset_num):
        self._clear_proxy()
        r = self.session.put(
            f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/presets/{preset_num}/goto',
            auth=self.auth, timeout=5)
        return r.status_code == 200

    def save_preset(self, preset_num, preset_name='HOME'):
        self._clear_proxy()
        xml = f'<PTZPreset><enabled>true</enabled><id>{preset_num}</id><presetName>{preset_name}</presetName></PTZPreset>'.encode('utf-8')
        r = self.session.put(
            f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/presets/{preset_num}',
            data=xml, auth=self.auth, timeout=5)
        return r.status_code == 200

    def get_capabilities(self):
        self._clear_proxy()
        try:
            r = self.session.get(
                f'http://{self.ip}/ISAPI/PTZCtrl/channels/1/capabilities',
                auth=self.auth, timeout=5)
            return r.text if r.status_code == 200 else ''
        except Exception:
            return ''

    def restore_all_defaults(self):
        self._clear_proxy()
        results = {}
        endpoints = [
            ('/ISAPI/Image/channels/1/color',
             b'<Color><brightnessLevel>50</brightnessLevel><contrastLevel>50</contrastLevel><saturationLevel>50</saturationLevel></Color>'),
            ('/ISAPI/Image/channels/1/exposure',
             b'<Exposure><ExposureType>auto</ExposureType><OverexposeSuppress><enabled>false</enabled></OverexposeSuppress></Exposure>'),
            ('/ISAPI/Image/channels/1/whiteBalance',
             b'<WhiteBalance><WBMode>auto</WBMode></WhiteBalance>'),
        ]
        for ep, data_xml in endpoints:
            try:
                r = self.session.put(f'http://{self.ip}{ep}', data=data_xml, auth=self.auth, timeout=5)
                results[ep] = r.status_code == 200
            except Exception:
                results[ep] = False
        return results

