def _get_error_hint(status_code):
    hints = {
        401: '请检查密码是否正确，确认设备账号为 admin',
        403: '请联系设备管理员确认账号权限',
        404: '请确认设备 IP 是否正确，设备是否在线',
        500: '设备异常，尝试重启设备后重试',
        'TIMEOUT': '请确认网络连接正常，设备 IP 是否可达',
        'CONNECTION': '请确认设备 IP 正确，网线连接正常',
    }
    return hints.get(status_code, '')

def authenticate(ip):
    creds = load_credentials() or []
    for c in creds:
        if c.get('ip') == ip and c.get('password'):
            acct = c.get('account', 'admin')
            ok, code, msg = verify_auth(ip, acct, c['password'])
            if ok:
                log_done(f'Auth OK (saved) @{ip}')
                return (acct, c['password'])
            else:
                log_warn(f'Saved creds failed @{ip}: {msg}')
                if code:
                    hint = _get_error_hint(code)
                    if hint:
                        log_warn(f'  提示: {hint}')

    attempt = 0
    while True:
        attempt += 1
        try:
            pw = getpass.getpass(f'  [{attempt}] Password (admin@{ip}): ')
        except (EOFError, KeyboardInterrupt):
            log_err('Input closed, exit')
            sys.exit(0)
        if pw.lower() == 'q':
            log_info('Auth cancelled by user')
            sys.exit(0)
        if not pw.strip():
            continue

        ok, code, msg = verify_auth(ip, 'admin', pw.strip())
        if ok:
            save_credentials(ip, 'admin', pw.strip())
            log_done(f'Auth OK @{ip} (after {attempt} attempt(s))')
            return ('admin', pw.strip())

        err_display = msg
        if code:
            hint = _get_error_hint(code)
            if hint:
                err_display += f' - {hint}'
        log_err(f'Auth failed @{ip}: {err_display}')

    log_fail(f'Auth failed @{ip}')
    return None

