# ===== Wait until azimuth+elevation stable =====
def wait_stable(ptz, duration=2):
    interval = 0.1
    samples = int(duration / interval)
    az_prev, el_prev = None, None
    stable_start = None

    for _ in range(samples):
        time.sleep(interval)
        s = ptz.get_status(retries=0)  # fast: one attempt per sample
        az, el = s['azimuth'], s['elevation']

        if az == az_prev and el == el_prev:
            if stable_start is None:
                stable_start = time.time()
            if time.time() - stable_start >= duration:
                return True
        else:
            az_prev, el_prev = az, el
            stable_start = None

    return True

