var detectionState = { running: false, step: 0, totalSteps: 3, results: {} };
function startDetection() {
    var deviceIp = document.getElementById('advConnectDevice').value;
    if (!deviceIp) { showToast('warning', '请先选择设备'); return; }
    var device = allDevices.find(function(d) { return d.ip === deviceIp; });
    var btn = document.getElementById('btnStartDetection');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner" style="display:inline-block"></span> 检测中...';
    document.getElementById('detectionProgress').style.display = 'block';
    document.getElementById('detectionLog').innerHTML = '';
    detectionState = { running: true, step: 0, totalSteps: 3, results: {}, deviceIp: deviceIp, device: device };
    addDetectionLog('info', '开始一键检测: ' + deviceIp);
    runDetectionStep();
}
function runDetectionStep() {
    var state = detectionState;
    if (!state.running) return;
    var steps = [
        { name: '功能检测', url: '/api/v1/advanced/function/run', key: 'function' },
        { name: '限位检测', url: '/api/v1/advanced/limit/run', key: 'limit' },
        { name: '速度检测', url: '/api/v1/advanced/speed/run', key: 'speed' }
    ];
    if (state.step >= steps.length) {
        finishDetection();
        return;
    }
    var stepInfo = steps[state.step];
    var pct = Math.round(((state.step) / state.totalSteps) * 100);
    document.getElementById('detectionProgressText').textContent = '步骤 ' + (state.step + 1) + '/' + state.totalSteps + ': ' + stepInfo.name;
    document.getElementById('detectionProgressBar').style.width = pct + '%';
    addDetectionLog('info', '▶ 运行 ' + stepInfo.name + '...');
    apiPost(stepInfo.url, {
        device_ip: state.deviceIp,
        username: (state.device && state.device.username) || 'admin',
        password: (state.device && state.device.password) || '',
        port: (state.device && state.device.port) || 80
    }).then(function(resp) {
        if (resp && resp.success) {
            state.results[stepInfo.key] = resp.results || {};
            addDetectionLog('success', '✅ ' + stepInfo.name + ' 完成');
        } else {
            addDetectionLog('error', '❌ ' + stepInfo.name + ' 失败: ' + (resp ? resp.message : '未知'));
        }
        state.step++;
        var newPct = Math.round((state.step / state.totalSteps) * 100);
        document.getElementById('detectionProgressBar').style.width = newPct + '%';
        runDetectionStep();
    }).catch(function(e) {
        addDetectionLog('error', '❌ ' + stepInfo.name + ' 异常: ' + e.message);
        state.step++;
        runDetectionStep();
    });
}
function finishDetection() {
    var btn = document.getElementById('btnStartDetection');
    btn.disabled = false;
    btn.innerHTML = '▶ 开始检测（全部）';
    document.getElementById('detectionProgressText').textContent = '检测完成！';
    document.getElementById('detectionProgressBar').style.width = '100%';
    document.getElementById('detectionProgressBar').className = 'progress-fill green';
    var state = detectionState;
    var completed = Object.keys(state.results).length;
    addDetectionLog('info', '=== 检测完成: ' + completed + '/' + state.totalSteps + ' 项通过 ===');
    // 显示完整结果
    if (completed > 0) {
